/* BASIC SETUP */
.page {
  box-sizing: border-box;
  padding: 100px;
  background-color: #FFFFFF;
  color: #111111;
  font-family: system-ui, -apple-system, BlinkMacSystemFont, "PingFang SC", "Microsoft YaHei", sans-serif;
  letter-spacing: 0;
  text-wrap: pretty;
}

/* PAGE-SPECIFIC LAYOUT */
.page-04 {
  justify-content: flex-start; /* Align items from the top */
  gap: 72px; /* Space between title and list */
}

/* HEADER & TITLE */
.page-header {
  width: 100%;
}

.page-title {
  font-size: 112px;
  font-weight: 600;
  line-height: 1.35;
  margin: 0;
  padding: 0;
  color: #111111;
}

/* CONTENT LIST */
.content-list {
  display: flex;
  flex-direction: column;
  gap: 32px; /* Space between list items */
  width: 100%;
}

.list-item {
  background-color: #F7F7F7;
  border-radius: 16px;
  padding: 40px;
  display: flex;
  flex-direction: column;
  gap: 16px;
}

.list-tag {
  margin: 0;
  padding: 0;
  font-size: 34px;
  font-weight: 600;
  color: #888888;
}

.list-text {
  margin: 0;
  padding: 0;
  font-size: 40px;
  line-height: 1.6;
  font-weight: 400;
  color: #333333;
  text-wrap: balance;
}

/* Universal page styles are handled by the system */
.page-05 {
  justify-content: flex-start;
  gap: 72px;
  background-color: #FDFDFD;
}

.page-title {
  color: #111111;
  font-size: 112px;
  font-weight: 600;
