  font-size: 40px;
  font-weight: 600;
  line-height: 1.4;
}

.card-text {
  margin: 0;
  color: #333333;
  font-size: 42px;
  font-weight: 400;
  line-height: 1.65;
  text-wrap: pretty;
}

main.page-06 {
    justify-content: flex-start;
    gap: 80px;
}

.page-header {
    display: flex;
    flex-direction: column;
}

.page-title {
    font-size: 132px;
    font-weight: bold;
    line-height: 1.25;
    margin: 0;
    color: #111;
}

.page-subtitle {
    font-size: 56px;
    line-height: 1.5;
    margin-top: 16px;
    color: #444;
}

.content-body {
    display: flex;
    flex-direction: column;
    gap: 60px;
}

.summary-card {
    background-color: #F7F7F7;
    padding: 32px;
    border-radius: 16px;
    display: flex;
    flex-direction: column;
    gap: 16px;
}

.proof-tag {
    align-self: flex-start;
    font-size: 36px;
    font-weight: 500;
    color: #111;
    background-color: #ECECEC;
    padding: 6px 18px;
    border-radius: 8px;
}

.proof-text {
    font-size: 40px;
    line-height: 1.6;
    color: #333;
    margin: 0;
}

.steps-list {
    list-style: none;
    padding-left: 0;
    margin: 0;
    display: flex;
    flex-direction: column;
    gap: 40px;
    counter-reset: steps-counter;
}

.step-item {
    font-size: 40px;
    line-height: 1.65;
    color: #111;
    padding-left: 60px;
    position: relative;
}

.step-item::before {
    counter-increment: steps-counter;
    content: counter(steps-counter);
    position: absolute;
    left: 0;
    top: 5px;
    font-size: 42px;
    font-weight: bold;
    color: #FFFFFF;
    background-color: #111;
    width: 42px;
    height: 42px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    line-height: 1;
}

.nowrap {
    white-space: nowrap;
}

